const e = $json || {};
const wf = (e.workflow && e.workflow.name) || 'unknown';
const node = (e.execution && e.execution.lastNodeExecuted) || 'unknown';
const msg  = (e.execution && e.execution.error && e.execution.error.message) || 'no message';
const when = new Date().toISOString();
return [{ json: {
  level: 'error',
  workflow: wf,
  node,
  message: msg,
  when,
  payload: { execId: e.execution?.id, retryOf: e.execution?.retryOf }
}}];
